<template>
  <div class="banner">
    <div class="banner__wrapper">
      <p class="banner__time">{{ time }}</p>
      <p class="banner__date">
        <span>{{ day }}</span> {{ fullDate }}
      </p>
      <h1 class="banner__title">{{ greetings }}</h1>
    </div>
    <div class="banner__wrapper">
      <div class="banner__length">
        <div class="banner__length-number">{{ allTasks.length }}</div>
        <p class="banner__length-title">Задач</p>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  data() {
    return {
      greetings: "Добрый день 👋",
      time: 0,
      fullDate: "",
      day: "",
    };
  },
  computed: {
    allTasks() {
      return this.$store.getters.tasks;
    },
  },
  mounted() {
    this.date();
    setInterval(() => {
      this.date();
    }, 1000);
  },
  methods: {
    date() {
      const date = new Date();
      let time = `${
          date.getHours() < 10 ? "0" + date.getHours() : date.getHours()
      } : ${
          date.getMinutes() < 10 ? "0" + date.getMinutes() : date.getMinutes()
      } : ${
          date.getSeconds() < 10 ? "0" + date.getSeconds() : date.getSeconds()
      }`;

      let fullDate = `${
          date.getDate() < 10 ? "0" + date.getDate() : date.getDate()
      }-${
          date.getMonth() + Number(1) < 10
              ? "0" + Number(date.getMonth() + 1)
              : date.getMonth() + Number(1)
      }-${date.getFullYear()}`;

      this.time = time;
      this.fullDate = fullDate;

      const days = ["Вс", "Пн", "Вт", "Ср", "Чт", "Пт", "Сб"];
      this.day = days[date.getDay()];

      if (days[date.getDay()] == "Сб" || days[date.getDay()] == "Вс") {
        this.greetings = "Хороших выходных 😉";
      } else if (date.getHours() >= 4 && date.getHours() < 12) {
        this.greetings = "Доброе утро 👋";
      } else if (date.getHours() >= 12 && date.getHours() < 18) {
        this.greetings = "Добрый день 🙂";
      } else if (date.getHours() >= 18 && date.getHours() <= 20) {
        this.greetings = "Добрый вечер 🌙";
      } else {
        this.greetings = "Спокойной ночи 🌗";
      }
    },
  },
};
</script>

<style lang="scss" scoped>
.banner {
  width: 100%;
  height: 120px;
  padding: 17px;
  margin-top: 10px;
  display: flex;
  justify-content: space-between;
  border-radius: 15px;
  background: linear-gradient(to bottom right, #ff6a28, #fe2f57);


  .banner__wrapper {
    display: flex;
    flex-direction: column;
  }

  .banner__length {
    text-align: center;

    .banner__length-number {
      font-size: 30px;
      font-weight: 800;
    }

    .banner__length-title {
      font-size: 13px;
    }
  }

  .banner__time {
    margin-top: 0px;
    font-size: 22px;
    font-weight: 700;
  }

  .banner__date {
    margin-top: 2px;
    font-size: 15px;

    span {
      font-weight: 900;
    }
  }

  .banner__title {
    margin-top: 17px;
    font-size: 16px;
  }
}
</style>