<template>
  <div class="add-task">
    <div class="add-task__wrapper container">
      <div class="add-task__header">
        <div class="add-task__title">Добавление задачи</div>
        <button
            class="add-task__close"
            @click="$emit('closeModalAddTask')"
        ></button>
      </div>
      <input
          type="text"
          class="add-task__title-inp"
          placeholder="Задача . . ."
          v-model="task.title"
      />
      <div class="add-task__date">

        <div class="add-task__date-inp">
          <p class="add-task__date-text">Дата выполнения</p>
          <div class="add-task__date-block" @click="toggleDatePicker">
            <p class="add-task__date-title">{{ fullDate }}</p>
            <img class="add-task__date-icon" src="@/assets/icons/date.svg" alt="date">
          </div>
        </div>
      </div>

      <DatePicker mode="dateTime" v-model="selectedDate" class="add-task__custom-date" v-if="dateModal"
                  :min-date="new Date()" is-dark
                  is24hr/>

      <div class="add-task__subtask">
        <button class="add-task__subtask-add" @click="addSubTaskInp">
          Добавить Подзадачу
        </button>
        <div class="add-task__subtasks">
          <div
              class="add-task__subtask-inp"
              v-for="(subTaskInp, index) in subTasksInp"
              :key="index"
          >
            <input
                type="text"
                placeholder="Подзадача"
                v-model="subTasksInp[index]"
            />
            <button @click="removeSubTask(index)"></button>
          </div>
        </div>
      </div>
      <button class="add-task__add" @click="addTask()">
        Опубликовать задачу
      </button>
    </div>
  </div>
</template>

<script>
import Calendar from 'v-calendar/lib/components/calendar.umd'
import DatePicker from 'v-calendar/lib/components/date-picker.umd'

export default {
  components: {
    Calendar,
    DatePicker
  },
  data() {
    return {
      selectedDate: new Date(),
      fullDate: 'Выберите дату',
      tasks: [],
      dateModal: false,
      task: {
        title: '',
        completed: false,
        dateTime: '',
        systemDate: '',
        subTasks: [],
      },
      subTasksInp: [],
    };
  },
  watch: {
    selectedDate: function () {
      if (this.selectedDate == null) {
        this.fullDate = 'Выберите дату'
      } else {
        const date = this.selectedDate;
        this.fullDate =
            `${
                date.getDate() < 10 ? '0' + date.getDate() : date.getDate()
            }.${
                date.getMonth() < 10 ? '0' + Number(1 + date.getMonth()) : Number(1 + date.getMonth())
            }.${
                date.getFullYear()
            } | ${
                date.getHours() < 10 ? '0' + date.getHours() : date.getHours()
            } : ${
                date.getMinutes() < 10 ? '0' + date.getMinutes() : date.getMinutes()
            }`

        this.task.systemDate = date;
        this.task.dateTime = this.fullDate;

        console.log(this.fullDate)
      }
    }
  },
  computed: {
    allTasks() {
      return this.$store.getters.tasks;
    },
  },
  mounted() {
    if (this.allTasks) {
      this.tasks = this.allTasks;
    }
  },
  methods: {
    toggleDatePicker() {
      this.dateModal = !this.dateModal
    },
    addSubTaskInp() {
      this.subTasksInp.push("");
      console.log(this.subTasksInp);
    },
    removeSubTask(index) {
      console.log(index);
      this.subTasksInp.splice(index, 1);
    },
    rnadomId() {
      const date = new Date();
      return (
          date.getFullYear() *
          date.getDate() *
          date.getHours() *
          date.getMinutes() *
          date.getSeconds() *
          date.getMilliseconds()
      );
    },
    addTask() {
      if (this.task.title) {
        this.subTasksInp.forEach((item) => {
          this.task.subTasks.push({
            title: item,
            completed: false,
          });
        });

        this.tasks.unshift({
          title: this.task.title,
          completed: false,
          dateTime: this.task.dateTime,
          systemDate: this.task.systemDate,
          subTasks: this.task.subTasks,
          idTask: this.rnadomId(),
        });

        console.log(this.rnadomId())

        this.$store.commit("addTasks", this.tasks);
        this.$emit("addTasks", this.tasks);
        localStorage.setItem("tasks", JSON.stringify(this.tasks));

        this.task.title = "";
        this.task.completed = false;
        this.task.dateTime = "";
        this.task.subTasks = [];
        this.subTasksInp = [];
        this.$emit("closeModalAddTask");
      }
    },
  },
};
</script>

<style lang="scss" scoped>
$blue: #1771f1;
$blue-hover: #095ed6;
$dark: #131313;

.add-task {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-color: #030303;
  color: #fff;
  z-index: 100;
  overflow: scroll;
  padding-bottom: 20px;

  &::-webkit-scrollbar {
    width: 0;
  }

  .add-task__wrapper {
    height: 100%;
    min-height: 500px;
  }

  .add-task__header {
    width: 100%;
    margin-top: 15px;
    display: flex;
    align-items: center;
    justify-content: space-between;

    .add-task__title {
      font-size: 17px;
    }

    .add-task__close {
      width: 20px;
      height: 20px;
      padding: 0;
      background: transparent;
      border-radius: 0;
      background-image: url(../assets/icons/close.svg);
      background-size: 80%;
      background-position: center;
      background-repeat: no-repeat;
    }
  }

  .add-task__title-inp {
    width: 100%;
    margin-top: 20px;
  }

  .add-task__date {
    width: 100%;
    margin-top: 20px;
    display: flex;
    flex-direction: column;

    .add-task__date-text {
      margin-left: 3px;
      font-size: 13px;
    }

    .add-task__date-block {
      width: 100%;
      height: 40px;
      margin-top: 5px;
      padding-left: 15px;
      padding-right: 15px;
      border-radius: 7px;
      display: flex;
      justify-content: space-between;
      align-items: center;
      background-color: $dark;
      color: #fff;
      font-size: 15px;
      font-weight: 400;

      .add-task__date-icon {
        max-width: 15px;
      }
    }
  }

  .add-task__custom-date {
    width: 100%;
    margin-top: 10px;
    color: var(--gray-100);
    background-color: $dark !important;
    border-color: var(--gray-700);
    border: none !important;
  }

  .add-task__subtask {
    margin-top: 20px;

    .add-task__subtask-add {
      width: 100%;
      height: 30px;
      padding: 0;
      border-radius: 5px;
      background: $dark;
      font-size: 14px;
      font-weight: 400;
    }

    .add-task__subtasks {
      margin-top: 10px;
      display: flex;
      flex-direction: column;

      .add-task__subtask-inp {
        display: flex;
        align-items: center;
        border-radius: 10px;
        background-color: #131313;

        &:not(:first-child) {
          margin-top: 5px;
        }

        input {
          width: 100%;
          height: 40px;
        }

        button {
          width: 40px;
          height: 40px;
          border-radius: 0;
          background-color: transparent;
          background-image: url(../assets/icons/close.svg);
          background-size: 30%;
          background-repeat: no-repeat;
          background-position: center;
        }
      }
    }
  }

  .add-task__add {
    margin-top: 20px;
    width: 100%;
    height: 35px;
  }
}
</style>